import sys
from collections import deque

def solve(data: str) -> str:
    tokens = iter(map(int, data.split()))
    n, m = next(tokens), next(tokens)
    graph = [[] for _ in range(n)]
    for _ in range(m):
        left, right = next(tokens), next(tokens)
        graph[left].append(right); graph[right].append(left)
    start, goal = next(tokens), next(tokens)
    frontier = deque([(start, 0)])
    seen = {start}
    while frontier:
        node, distance = frontier.popleft()
        if node == goal:
            return str(distance)
        for neighbor in graph[node]:
            if neighbor not in seen:
                seen.add(neighbor); frontier.append((neighbor, distance + 1))
    return 'unreachable'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
